def gen(rng, size):
    n = rng.randint(2, min(13, max(2, size)))
    graph = [[] for _ in range(n)]
    # edges only go from lower to higher index => acyclic
    for u in range(n):
        for v in range(u + 1, n):
            if rng.random() < 0.45:
                graph[u].append(v)
    # ensure node 0 reaches n-1 and is not isolated where possible
    # guarantee a spine path 0 -> ... -> n-1 by linking gaps
    reachable = set([0])
    order = list(range(n))
    for u in order:
        if u in reachable:
            for v in graph[u]:
                reachable.add(v)
    if (n - 1) not in reachable:
        graph[0].append(n - 1)
        graph[0] = sorted(set(graph[0]))
    return [graph]

