var allPathsSourceTarget = function(graph) {
    const n = graph.length;
    const target = n - 1;
    const res = [];
    const path = [0];
    function dfs(node) {
        if (node === target) {
            res.push(path.slice());
            return;
        }
        for (const nb of graph[node]) {
            path.push(nb);
            dfs(nb);
            path.pop();
        }
    }
    dfs(0);
    res.sort((a, b) => {
        const m = Math.min(a.length, b.length);
        for (let i = 0; i < m; i++) if (a[i] !== b[i]) return a[i] - b[i];
        return a.length - b.length;
    });
    return res;
};
